function Car(n){var a=this,e=$("#"+n);this.tabID=n,this.showVendor=function(){var n=e.find("[name=chkIsVendor]").val(),a=e.find(".vendor");1==n?a.show():a.hide()},this.updateVolumeChange=function(){var n=(parseFloat(unformatCurrency(e.find("[name=length]").val()))||0)*(parseFloat(unformatCurrency(e.find("[name=width]").val()))||0)*(parseFloat(unformatCurrency(e.find("[name=height]").val()))||0);e.find("[name='cbm']").val(n).blur()},this.rebindEl=function(){},this.loadOnReady=function(){e.find("[name=chkIsVendor]").on("change",function(){a.showVendor()}),e.find("[name=length], [name=width], [name=height]").change(function(){a.updateVolumeChange()}),a.rebindEl()}}